VALUES
  ('social-worker-moex-08020', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '20 世紀後半葉西方社會發生所謂的「新社會運動」，下列何者並非屬於「新社會運動」下的福利意識形 態？', '["批判福利國家缺乏性別意識，追求性別平等的女性主義", "批判資本主義剝削，追求階級平等的社會主義", "反對種族主義，追求族群平等的多元文化主義", "反對單一理性過度決定，追求免於各種結構性壓制的後現代主義"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08021', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有些社會偶發事件，往往激發社會大眾的集體意識，從而直接或間接推動社會福利政策方案排進議程。 這類的社會偶發事件，可歸為那種社會政策形成的因素？', '["情境因素", "結構因素", "文化因素", "環境因素"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08022', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '「僱用曾受專業訓練之社會工作人員，負責推進各項工作」的主張，係源自下列那個政策？', '["民國54年的「民生主義現階段社會政策」", "民國58年的「現階段社會建設綱領」", "民國70年的「貫徹復興基地民生主義社會經濟建設方案」", "民國83年的「社會福利政策綱領」"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08023', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '「社會排除」概念在全球的廣泛流通，係與下列何者有關？', '["馬克思主義者的倡導", "多元文化主義者的行銷", "法國社會福利學者的創用", "歐盟（EU）的政策主張"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08024', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '1980年代歐洲「福利國家」之所以陷入財務危機，大致與舉辦下列何種社會福利制度最為有關？', '["個別性社會福利服務", "全民健康保險", "年金保險", "社會救助"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "7ddba145c519", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
